    },
    {
      "n": 9,
      "column": "left",
      "text": "Gewrains taps par Tuḱ-\nnesi tai Sohdibas Deena/ starp\ntahn Israeta Ziltim. Es etmu\nfinnamu darrijs/ ka tas teefscham\nnotifs.\n"
    },
    {
      "n": 10,
      "column": "left",
      "text": "Ee Leeli-Kungi no Juḥ-\nda irr tappuschi ka tee/\nkas to Rohbeschu pahr-\nzett/ es isgahsfischu pahr teein\nfawn Apstaischanu ka Uhdeni.\n"
    },
    {
      "n": 11,
      "column": "left",
      "text": "Gewrains tohp apbehdi-\nnahts/ un nospaidihts Sohda/\njo winnam ta gribbejahs/ wiſch\nirr (Zilweku) Banfleem pakkat-\ndsinnees.\n"
    },
    {
      "n": 12,
      "column": "left",
      "text": "Tapehz buhſchu es Ee-\nwraimain ka Kohde / un tam\nNamnam Juhda ka Kahpuris.\n"
    },
    {
      "n": 13,
      "column": "left",
      "text": "Rad Gewrains fanu\nSehrgu redſeja/ un Juhda fa-\ntwu Tuhkumu/ tad zehlahs Ee-\nwraims pee Affura / un fuhtija\npee ta Jareba Kehnita / bet tas\n"
    },
    {
      "n": 14,
      "column": "right",
      "text": "Jo es buhſchu Eet-\nmam ka Lauwa/ un tam N\nmam Juhda ka jauns Lau\nEs/ es faplohfitchu / un ee\nprohjam/ es aiswedifchu/\nbuhs neweens Jeglabbeis.\n"
    },
    {
      "n": 15,
      "column": "right",
      "text": "Es eefchu unn atgr\nschohs uhs mannu Weetu /\nkans tee fawn Noseegumu\nſihst/ un mannu Waign m\n"
    },
    {
      "n": 1,
      "column": "right",
      "text": "Rad teem bali buhs/\ntee mannis agri meklehs. Et\natgreeſifimees pee ta KUNG\nJo Wiſch irr faplohtijs /\nWiſch muhs dseedina\nWiſch irr fakuhlis/ ir Wi\nmuhs afsfees.\n"
    },
    {
      "n": 2,
      "column": "right",
      "text": "Wiſch darrihs muhs\nwus pehz diwi Deenahm/ tre\nDeena Wiſch muhs uszels\nmehs winna Preekſcha dsil\nfim.\n"
    },
    {
      "n": 3,
      "column": "right",
      "text": "Tad xemtim mehs wel\nmehs dsibstimees to KUNG\natsiht/ wiſch irr gattaws is\nka tas Aufeklis/ un nahks\nmunns ka stiprs Leetus/ ka\nlajs Leetus/ un agrajs Leetu\nto Semint.\n"
    },
    {
      "n": 4,
      "column": "right",
      "text": "Ko darriſchu es tew/ af\nwraims! ko darriſchu es tei\nJuhda! Jo ta Schehlastiba/\njums notifs / buhs ka tw\nagruma Padebbes/ un agri\ndana Raffa/ kas ateet.\n"
    },
    {
      "n": 5,
      "column": "right",
      "text": "Tadeht esmu es tohs\npais zaur teem Praueefchee\n"
    }
